async function getPoolData(tokenA, tokenB, fee, provider) {
  // Uniswap V3 factory contract address and ABI
  const uniswapV3FactoryAddress = "0x1F98431c8aD98523631AE4a59f267346ea31F984";
  const uniswapV3FactoryABI = [
    {
      inputs: [
        { internalType: "address", name: "tokenA", type: "address" },
        { internalType: "address", name: "tokenB", type: "address" },
        { internalType: "uint24", name: "fee", type: "uint24" },
      ],
      name: "getPool",
      outputs: [{ internalType: "address", name: "pool", type: "address" }],
      stateMutability: "view",
      type: "function",
    },
  ];

  // Get the Uniswap V3 pool address
  const uniswapV3FactoryContract = new ethers.Contract(
    uniswapV3FactoryAddress,
    uniswapV3FactoryABI,
    provider
  );
  const poolAddress = await uniswapV3FactoryContract.getPool(tokenA, tokenB, fee);

  // Uniswap V3 pool contract ABI
  const uniswapV3PoolABI = [
    { inputs: [], name: "slot0", outputs: [{ internalType: "uint160", name: "", type: "uint160" }], stateMutability: "view", type: "function" },
    { inputs: [], name: "liquidity", outputs: [{ internalType: "uint128", name: "", type: "uint128" }], stateMutability: "view", type: "function" },
  ];

  // Get pool's data
  const poolContract = new ethers.Contract(poolAddress, uniswapV3PoolABI, provider);
  const [slot0, liquidity] = await Promise.all([poolContract.slot0(), poolContract.liquidity()]);

  // Create a Pool instance
  const tokenIn = new Token(chainId, tokenA, await getTokenDecimals(tokenA));
  const tokenOut = new Token(chainId, tokenB, await getTokenDecimals(tokenB));
  const pool = new Pool(tokenIn, tokenOut, fee, slot0, liquidity, 0);

  return pool;
}

async function getTokenDecimals(tokenAddress) {
  if (!ethers.utils.isAddress(tokenAddress)) {
    throw new Error("Address is not valid");
  }

  const abi = ["function decimals() view returns (uint8)"];
  const tokenContract = new ethers.Contract(tokenAddress, abi, provider);
  return await tokenContract.decimals();
}
```

